import pytest
import requests

def test_breakglass_non_clinician_role_is_denied(
    base_url, nurse_admin_token, existing_patient_id, get_latest_audit_event
):
    payload = {
        "patientId": existing_patient_id,
        "reason": "Testing unauthorized access"
    }
    headers = {"Authorization": f"Bearer {nurse_admin_token}"}

    resp = requests.post(f"{base_url}/BreakGlass", json=payload, headers=headers)

    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert "error" in body or "message" in body, "Error field missing in 403 response"

    audit = get_latest_audit_event(patient_id=existing_patient_id, event_type="BREAK_GLASS")
    assert audit is None, "No BREAK_GLASS audit event should be created for rejected request"
